/*
 * Logic for extracting the immediate value for M-, I-, and RI-format
 * instructions.
 * STUDENT TO-DO:
 * Extract the immediate value and write it to *imm.
 */
static comb_logic_t extract_immval(uint32_t insnbits, opcode_t op,
                                   int64_t *imm) {
    switch (op) {
        case OP_LDUR:
        case OP_STUR:
            *imm = bitfield_s64(insnbits, 12, 9);
            break;
        case OP_MOVK:
        case OP_MOVZ:
            *imm = bitfield_u32(insnbits, 5, 16);
            break;
        case OP_ADD_RI:
        case OP_SUB_RI:
            *imm = bitfield_u32(insnbits, 10, 12);
            break;
        case OP_LSL_RI:
            *imm = 63 - bitfield_u32(insnbits, 10, 6);
            break;
        case OP_LSR_RI:
        case OP_ASR:
            *imm = bitfield_u32(insnbits, 16, 6);
            break;
        case OP_ADRP:
            int64_t immhi = bitfield_s64(insnbits, 5, 19);
            uint32_t immlo = bitfield_u32(insnbits, 29, 2);
            *imm = ((immhi << 2) | immlo) << 12;
            break;
        case OP_B:
        case OP_BL:
            *imm = bitfield_s64(insnbits, 0, 26) << 2;
            break;
        case OP_B_COND:
            *imm = bitfield_s64(insnbits, 5, 19) << 2;
            break;
        default:
            break;
    }
    return;
}

/*
 * Logic for determining the ALU operation needed for this opcode.
 * STUDENT TO-DO:
 * Determine the ALU operation based on the given opcode
 * and write it to *ALU_op.
 */
static comb_logic_t decide_alu_op(opcode_t op, alu_op_t *ALU_op) {
    switch (op)
    {
        case OP_NOP:
        case OP_B:
        case OP_B_COND:
        case OP_BL:
        case OP_RET:
        case OP_HLT:
            *ALU_op = PASS_A_OP;
            break;
        
        case OP_LDUR:
        case OP_STUR:
        case OP_ADRP:
        case OP_ADD_RI:
        case OP_ADDS_RR:
        case OP_CMN_RR:
            *ALU_op = PLUS_OP;
            break;

        case OP_SUB_RI:
        case OP_SUBS_RR:
        case OP_CMP_RR:
            *ALU_op = MINUS_OP;
            break;

        case OP_ANDS_RR:
        case OP_TST_RR:
            *ALU_op = AND_OP;
            break;

        case OP_LSL_RI:
        case OP_LSL_RR:
            *ALU_op = LSL_OP;
            break;

        case OP_LSR_RI:
        case OP_LSR_RR:
            *ALU_op = LSR_OP;
            break;

        case OP_ASR:
            *ALU_op = ASR_OP;
            break;
        
        case OP_MVN:
            *ALU_op = INV_OP;
            break;
        
        case OP_ORR_RR:
            *ALU_op = OR_OP;
            break;
        
        case OP_EOR_RR:
            *ALU_op = EOR_OP;
            break;

        case OP_MOVZ:
            *ALU_op = MOV_OP;
            break;

        case OP_MOVK:
            *ALU_op = MOVK_OP;
            break;
        
    default:
        break;
    }
}

